var cherryPickup = function(grid) {
    const N = grid.length;
    const memo = new Array(N).fill(0).map(() => new Array(N).fill(0).map(() => new Array(N).fill(Number.MIN_SAFE_INTEGER)));

    function dp(r1, c1, c2) {
        const r2 = r1 + c1 - c2;
        if (r1 === N || r2 === N || c1 === N || c2 === N || grid[r1][c1] === -1 || grid[r2][c2] === -1) {
            return Number.MIN_SAFE_INTEGER;
        } else if (r1 === N - 1 && c1 === N - 1) {
            return grid[r1][c1];
        } else if (memo[r1][c1][c2] !== Number.MIN_SAFE_INTEGER) {
            return memo[r1][c1][c2];
        } else {
            memo[r1][c1][c2] = grid[r1][c1] + (r1 !== r2 ? grid[r2][c2] : 0);
            const tempMax = Math.max(Math.max(dp(r1 + 1, c1, c2 + 1), dp(r1, c1 + 1, c2 + 1)),
                            Math.max(dp(r1 + 1, c1, c2), dp(r1, c1 + 1, c2)));
            memo[r1][c1][c2] += tempMax;
        }
        return memo[r1][c1][c2];
    }

    return Math.max(0, dp(0, 0, 0));
};
```


    The algorithm is based on Dynamic Programming. The main idea is to traverse the grid twice - first from (0, 0) to (n-1, n-1) and then back to (0, 0) - using two different paths.

We use memoization to store values of the cherries collected at each step to avoid recomputations. The dp function takes three variables (r1, c1, and c2) as inputs, where r1 and c1 represent the row and column of the first path, and c2 represents the column of the second path. We then calculate the row of the second path (r2) using the formula r2 = r1 + c1 - c2.

The function checks the base cases for invalid inputs or if cherries collected are already calculated (memoized), then it returns the memoized value.

The main algorithm calculates the cherries for the current step by adding the cherries in the current cell r1 and c1, and if the paths are different, it adds cherries of r2 and c2 too. After that, it computes the maximum cherries from four possible ways to move (right, down) for both paths and adds it to the memoized table.

Finally, the algorithm returns memo[r1][c1][c2] as the maximum cherries collected.

At the end, the function returns the maximum cherries collected between (0, 0) and (n-1, n-1) using two different paths, making sure it's not negative.

